# 不错的防止别人查看页面的代码,用来保护网站版权
````
<!--onselectstart:禁止选中 oncontextmenu:右键弹出版权 event.keyCode==27:按esc键表示放弃Esc键阻止网页继续载入,也就是说你按ESC键网页还是继续加载-->
<body onselectstart="return false;" oncontextmenu="alert('请尊重本网站版权！');return false;" onkeydown="if(event.keyCode==27) return false;">
<script type="text/javascript">
document.onmousedown = click;  //绑定禁用鼠标右键事件
document.onkeydown = ctrl_key; //绑定禁用键盘事件
function click() {
if (event.button == 2)      //单击的鼠标键为右键
{
alert('请尊重本网站版权！');
return false;
}
}
function ctrl_key() {
if (event.keyCode == 17) {                          //禁用CTRL+S 保存网页代码
window.alert("请尊重本网站版权！");
return false;
}
if (event.keyCode == 123) {                         //禁用F12查看源代码
alert('请尊重本网站版权！');
return false;
}
}
</script>
````

### 一、根目录
**1、LinuxApache环境(.htaccess)：**

```
 <IfModule mod_rewrite.c>
 RewriteEngine On
 \# 下面是在根目录，文件夹要修改路径，如 /laozuo/
 RewriteBase /
 RewriteCond %{REQUEST_FILENAME} !-f
 RewriteCond %{REQUEST_FILENAME} !-d
 RewriteRule ^(.*)$ /index.php/$1 [L]

 \# 带 www 的跳转到不带的
 RewriteCond %{HTTP_HOST} ^www.laozuo.org
 RewriteRule (.*) http://laozuo.org/$1 [R=301,L]

 \# 不带 www 的跳转到带的
 RewriteCond %{HTTP_HOST} ^laozuo.org
RewriteRule (.*) https://www.laozuo.org/$1 [R=301,L]
 </IfModule>
```
**2、LinuxApache环境（Nginx）：**
```
 location / {
 index index.html index.php;
 if (-f $request_filename/index.html) {
 rewrite (.*) $1/index.html break;
 }
 if (-f $request_filename/index.php) {
 rewrite (.*) $1/index.php;
 }
 if (!-f $request_filename) {
 rewrite (.*) /index.php;
 }
 }
```
**3、Windows IIS伪静态(httpd.ini)：**
```
 [ISAPI_Rewrite]
 # 3600 = 1 hour
 CacheClockRate 3600
 RepeatLimit 32
 # 中文tag解决
 RewriteRule /tag/(.*) /index\.php\tag=$1
 # sitemapxml
 RewriteRule /sitemap.xml /sitemap.xml [L]
 RewriteRule /favicon.ico /favicon.ico [L]
 # 内容页
 RewriteRule /(.*).html /index.php/$1.html [L]
 # 评论
 RewriteRule /(.*)/comment /index.php/​$1/comment [L]
 # 分类页
 RewriteRule /category/(.*) /index.php/category/$1 [L]
 # 分页
 RewriteRule /page/(.*) /index.php/page/$1 [L]
 # 搜索页
 RewriteRule /search/(.*) /index.php/search/​$1 [L]
 # feed
 RewriteRule /feed/(.*) /index.php/feed/$1 [L]
 # 日期归档
 RewriteRule /2(.*) /index.php/2$1 [L]
 # 上传图片等
 RewriteRule /action(.*) /index.php/action​$1 [L]
```
